320	  const { data, isLoading, error, mutate } = useSWR(
321	    `${s3Client.providerType}-${bucketName}-${BUCKET_LIFECYCLE_RULE_CACHE_KEY_SUFFIX}`,
322	    () => s3Client.getBucketLifecycleConfiguration({ Bucket: bucketName }),
323	    {
324	      shouldRetryOnError: false,
325	    }
326	  );
