330	  const rules: LifecycleRule[] = noRuleExistsError ? [] : data?.Rules || [];
331	  const loaded = !isLoading && fresh;
332	  const providerType = s3Client.providerType as S3ProviderType;
333	  const createRuleLink = `${getBucketOverviewBaseRoute(bucketName, providerType)}/management/lifecycle/create/~new`;
334	
335	  const [unfilteredRules, filteredRules, onFilterChange] = useListPageFilter(
336	    rules,
337	    nameFilterOverride
338	  );
339	
340	  React.useEffect(() => {
341	    if (!fresh) mutate();
342	  }, [fresh, mutate]);
343	
344	  if (!loaded || (error && !noRuleExistsError)) {
345	    return (
346	      <StatusBox
347	        loaded={loaded}
348	        loadError={!loaded ? '' : error}
349	        skeleton={<div className="loading-skeleton--table pf-v6-u-mt-lg" />}
350	      />
351	    );
352	  }
353	
354	  return (
355	    <>
356	      <ListPageHeader title={t('Lifecycle rules')}>
357	        {!!rules.length && (
358	          <ListPageCreateLink to={createRuleLink}>
359	            {t('Create lifecycle rule')}
360	          </ListPageCreateLink>
361	        )}
362	      </ListPageHeader>
363	      <ListPageBody>
364	        {!rules.length ? (
365	          <EmptyPage
366	            title={t(
367	              'No lifecycle rules defined for the objects in your bucket.'
368	            )}
369	            buttonText={t('Create lifecycle rule')}
370	            onClick={() => navigate(createRuleLink)}
371	            isLoaded
372	            canAccess
373	          />
374	        ) : (
375	          <>
376	            <ListPageFilter
377	              data={unfilteredRules}
378	              loaded
379	              hideLabelFilter={true}
380	              onFilterChange={onFilterChange}
381	              hideColumnManagement={true}
382	            />
383	            <RulesTable
384	              data={filteredRules}
385	              unfilteredData={rules}
386	              loaded
387	              loadError={null}
388	              rowData={{
389	                navigate,
390	                launcher,
391	                mutate,
392	                s3Client,
393	                bucketName,
394	              }}
395	            />
396	          </>
397	        )}
398	      </ListPageBody>
399	    </>
400	  );
401	};

