309	export const LifecycleRulesList: React.FC<LifecycleRulesListProps> = ({
310	  obj: { fresh },
311	}) => {
312	  const { t } = useCustomTranslation();
313	
314	  const { bucketName } = useParams();
315	  const navigate = useNavigate();
316	  const launcher = useModal();
317	  const { s3Client } = React.useContext(S3Context);
318	
319	  const { data, isLoading, error, mutate } = useSWR(
320	    `${s3Client.providerType}-${bucketName}-${BUCKET_LIFECYCLE_RULE_CACHE_KEY_SUFFIX}`,
321	    () => s3Client.getBucketLifecycleConfiguration({ Bucket: bucketName }),
322	    {
323	      shouldRetryOnError: false,
324	    }
325	  );
326	
327	  const noRuleExistsError = isNoLifecycleRuleError(error);
328	  // in case of "noRuleExistsError" error, cache could still have older "data", hence clearing that.
329	  const rules: LifecycleRule[] = noRuleExistsError ? [] : data?.Rules || [];
330	  const loaded = !isLoading && fresh;
331	  const providerType = s3Client.providerType as S3ProviderType;
332	  const createRuleLink = `${getBucketOverviewBaseRoute(bucketName, providerType)}/management/lifecycle/create/~new`;
333	
334	  const [unfilteredRules, filteredRules, onFilterChange] = useListPageFilter(
335	    rules,
336	    nameFilterOverride
337	  );
338	
339	  React.useEffect(() => {
340	    if (!fresh) mutate();
341	  }, [fresh, mutate]);
342	
343	  if (!loaded || (error && !noRuleExistsError)) {
344	    return (
345	      <StatusBox
346	        loaded={loaded}
347	        loadError={!loaded ? '' : error}
348	        skeleton={<div className="loading-skeleton--table pf-v6-u-mt-lg" />}
349	      />
350	    );
351	  }
352	
353	  return (
354	    <>
355	      <ListPageHeader title={t('Lifecycle rules')}>
356	        {!!rules.length && (
357	          <ListPageCreateLink to={createRuleLink}>
358	            {t('Create lifecycle rule')}
359	          </ListPageCreateLink>
360	        )}
361	      </ListPageHeader>
362	      <ListPageBody>
363	        {!rules.length ? (
364	          <EmptyPage
365	            title={t(
366	              'No lifecycle rules defined for the objects in your bucket.'
367	            )}
368	            buttonText={t('Create lifecycle rule')}
369	            onClick={() => navigate(createRuleLink)}
370	            isLoaded
371	            canAccess
372	          />
373	        ) : (
374	          <>
375	            <ListPageFilter
376	              data={unfilteredRules}
377	              loaded
378	              hideLabelFilter={true}
379	              onFilterChange={onFilterChange}
380	              hideColumnManagement={true}
381	            />
382	            <RulesTable
383	              data={filteredRules}
384	              unfilteredData={rules}
385	              loaded
386	              loadError={null}
387	              rowData={{
388	                navigate,
389	                launcher,
390	                mutate,
391	                s3Client,
392	                bucketName,
393	              }}
394	            />
395	          </>
396	        )}
397	      </ListPageBody>
398	    </>
399	  );
400	};
